#include <iostream>
#include <iomanip>

class Temperature {
private:
    double celsius;

public:
    void setCelsius(double c) {
        celsius = c;
    }

    double getCelsius() {
        return celsius;
    }

    void setFahrenheit(double f) {
        celsius = (f - 32.0) * 5.0 / 9.0;
    }

    double getFahrenheit() {
        return celsius * 9.0 / 5.0 + 32.0;
    }
};

int main() {
    Temperature temp;
    std::cout << std::fixed << std::setprecision(1);

    // Test case 1
    temp.setCelsius(25.0);
    std::cout << "C_to_F: " << temp.getFahrenheit() << "\n";

    // Test case 2
    temp.setFahrenheit(68.0);
    std::cout << "F_to_C: " << temp.getCelsius() << "\n";

    // Test case 3
    temp.setCelsius(0.0);
    std::cout << "C_to_F: " << temp.getFahrenheit() << "\n";

    // Test case 4
    temp.setFahrenheit(212.0);
    std::cout << "F_to_C: " << temp.getCelsius() << "\n";

    // Test case 5
    temp.setCelsius(-10.0);
    std::cout << "C_to_F: " << temp.getFahrenheit() << "\n";

    return 0;
}
